#!/bin/sh
# Claude Code status line — installer.
#
# Usage:
#   curl -fsSL .../install.sh | sh                # IP-based weather location
#   curl -fsSL .../install.sh | WITH_GPS=1 sh     # also installs CoreLocationCLI
#                                                   for GPS-based weather location
set -e

mkdir -p "$HOME/.claude"

# Optional: install a GPS helper so weather pings the right place.
if [ "${WITH_GPS:-0}" = "1" ]; then
  if command -v CoreLocationCLI >/dev/null 2>&1 || command -v whereami >/dev/null 2>&1; then
    echo "GPS helper already installed; skipping."
  elif command -v brew >/dev/null 2>&1; then
    echo "Installing CoreLocationCLI (you'll get a Location Services prompt on first use)..."
    brew install corelocationcli || echo "WARN: corelocationcli install failed; will fall back to IP."
  else
    echo "WARN: WITH_GPS=1 set but Homebrew not found; weather will use IP geolocation."
  fi
fi

# Write the statusline script.
printf %s '' \
  | base64 -d > "$HOME/.claude/statusline-command.sh"
chmod +x "$HOME/.claude/statusline-command.sh"

# Wire it up in settings.json.
SETTINGS="$HOME/.claude/settings.json"
[ -f "$SETTINGS" ] || echo "{}" > "$SETTINGS"
if command -v jq >/dev/null 2>&1; then
  tmp=$(mktemp)
  jq --arg cmd "sh $HOME/.claude/statusline-command.sh" \
    '.statusLine = {type:"command", command:$cmd}' "$SETTINGS" > "$tmp" \
    && mv "$tmp" "$SETTINGS"
else
  python3 - "$SETTINGS" <<'PY_CFG'
import json, os, sys
p = sys.argv[1]
try:
    d = json.load(open(p))
except Exception:
    d = {}
d["statusLine"] = {
    "type": "command",
    "command": "sh " + os.path.expanduser("~/.claude/statusline-command.sh"),
}
json.dump(d, open(p, "w"), indent=2)
PY_CFG
fi

echo "Statusline installed. Restart Claude Code to see it."
